const { ApolloServer, gql } = require('apollo-server');
const WebSocket = require('ws');

// Define the GraphQL schema
const typeDefs = gql`
  type Query {
    chatRooms: [ChatRoom]
  }

  type ChatRoom {
    id: ID!
    name: String!
  }

  type Subscription {
    chatMessage(roomId: ID!): ChatMessage
  }

  type ChatMessage {
    id: ID!
    message: String!
    sender: String!
  }
`;

// Define the resolvers for the schema
const resolvers = {
  Query: {
    chatRooms: () => [
      { id: '1', name: 'Chat Room 1' },
      { id: '2', name: 'Chat Room 2' },
    ],
  },
  Subscription: {
    chatMessage: (root, args) => {
      const roomId = args.roomId;
      const ws = new WebSocket('ws://localhost:8080/chat');
      ws.on('message', message => {
        console.log(`Received message from ${roomId}: ${message}`);
      });
      return { id: '1', message: 'Hello, world!', sender: 'User 1' };
    },
  },
};

// Create the Apollo Server instance
const server = new ApolloServer({ typeDefs, resolvers });

// Start the server
server.listen().then(({ url }) => {
  console.log(`Server started at ${url}`);
});